private void DataGrid_ContextMenuOpening(object sender, ContextMenuOpeningEventArgs e)
{
    // Customize or cancel the context menu
    if (e.MenuItems != null)
    {
        e.MenuItems.Add(new MenuItem { Text = ""Custom Action"", Command = ViewModel.CustomCommand });
    }

