                        ItemsSource="{Binding YourData}"
                        AutoGenerateColumns="True"
                        ContextMenuClosing="DataGrid_ContextMenuClosing"/>


## [C#]

private void DataGrid_ContextMenuClosing(object sender, ContextMenuClosingEventArgs e)
{
    // Optionally cancel the closing
    if (e.MenuItems.Any(item => item.Text == "Delete"))
    {
        e.Cancel = true;
    }

    // Access the column that triggered the menu
    var column = e.Column;
}

Here is an example of how to use the  class in the  event.

## [XAML]

<syncfusion:SfDataGrid x:Name="dataGrid"
                        ItemsSource="{Binding YourData}"
                        AutoGenerateColumns="True"
                        ContextMenuOpening="DataGrid_ContextMenuOpening" />


## [C#]

private void DataGrid_ContextMenuOpening(object sender, ContextMenuOpeningEventArgs e)
{
    // Add a custom menu item
    e.MenuItems.Add(new MenuItem { Text = "Refresh", Command = ViewModel.RefreshCommand });

    // Cancel the menu if needed
    if (e.Column.MappingName == "Status")
    {
        e.Cancel = true;
    }
}

Here is an example of how to use the  class in the  event.

## [XAML]

<syncfusion:SfDataGrid x:Name="dataGrid"
                        ItemsSource="{Binding YourData}"
                        AutoGenerateColumns="True"
                        ContextMenuOpened="DataGrid_ContextMenuOpened" />


## [C#]

private void DataGrid_ContextMenuOpened(object sender, ContextMenuOpenedEventArgs e)
{
    // Log or inspect the opened menu items
    foreach (var item in e.MenuItems)
    {
        Console.WriteLine($"Opened Menu Item: {item.Text}");
    }

    // Access the column that triggered the menu
    var column = e.Column;
    Console.WriteLine($"Context menu opened for column: {column.MappingName}");
}

Here is an example of how to use the  class in the  event.

## [XAML]

<syncfusion:SfDataGrid x:Name="dataGrid"
                        ItemsSource="{Binding YourData}"
                        AutoGenerateColumns=""True"
                        ContextMenuItemClicked="DataGrid_ContextMenuItemClicked" />


## [C#]

private void DataGrid_ContextMenuItemClicked(object sender, ContextMenuItemClickedEventArgs e)
{
    var clickedItem = e.MenuItem;
    Console.WriteLine($"Clicked Menu Item: {clickedItem.Text}");

    // Perform action based on the clicked item
    if (clickedItem.Text == "Edit")
    {
        ViewModel.EditSelectedRecord();
    }
}

Here is an example of how to use the  class in the  event.

## [XAML]

<syncfusion:SfDataGrid x:Name="dataGrid"
                        ItemsSource="{Binding YourData}"
                        AutoGenerateColumns="True"
                        ContextMenuClosed="DataGrid_ContextMenuClosed" />


## [C#]

private void DataGrid_ContextMenuClosed(object sender, ContextMenuClosedEventArgs e)
{
    // Perform cleanup or update UI after the menu is closed
    Console.WriteLine("Context menu closed.");

    // Access the column that triggered the menu
    var column = e.Column;

    // Inspect the menu items that were displayed
    foreach (var item in e.MenuItems)
    {
        Console.WriteLine($"Closed Menu Item: {item.Text}");
    }
}

example.code:
 public class CustomAggregate : ISummaryAggregate
 {
 public CustomAggregate()
  {
 }
 public double StdDev { get; set; }
 public Action<System.Collections.IEnumerable, string, System.ComponentModel.PropertyDescriptor>  CalculateAggregateFunc()
 {
  return (items, property, pd) =>
 {
 var enumerableItems = items as IEnumerable<OrderInfo>;
               if (pd.Name == "StdDev")
            {
             this.StdDev = enumerableItems.StdDev<OrderInfo>(q => q.OrderID);
       }
   };
 }
  }
 public static class LinqExtensions
 {
  public static double StdDev<T>(this IEnumerable<T> values, Func<T, double?> selector)
 {
  double value = 0;
var count = values.Count();
if (count > 0)
            {
             double? avg = values.Average(selector);
          double sum = values.Select(selector).Sum(d =>
       {
        if (d.HasValue)
     {
      return Math.Pow(d.Value - avg.Value, 2);
 }
  return 0.0;
 });
 value = Math.Sqrt((sum) / (count - 1));
}
   return value;
  }
 }

